This tests PRD 4 US-003 (custom codes on factory methods).

1. **e2e-test plugin** — Add plugins/e2e-test/src/tools/error-custom-code.ts:
```typescript
import { defineTool, ToolError } from '@opentabs-dev/plugin-sdk';
import { z } from 'zod';

export const errorCustomCode = defineTool({
  name: 'error_custom_code',
  displayName: 'Error Custom Code',
  description: 'Throws ToolError with custom code via factory methods',
  icon: 'alert-triangle',
  input: z.object({
    factory: z.enum(['auth', 'not_found', 'rate_limited', 'validation', 'timeout', 'internal']).describe('Which factory method to use'),
  }),
  output: z.object({ ok: z.boolean() }),
  handle: async (params) => {
    switch (params.factory) {
      case 'auth': throw ToolError.auth('Custom auth error', 'CUSTOM_AUTH');
      case 'not_found': throw ToolError.notFound('Custom not found', 'CUSTOM_NOT_FOUND');
      case 'rate_limited': throw ToolError.rateLimited('Custom rate limit', 5000, 'CUSTOM_RATE_LIMIT');
      case 'validation': throw ToolError.validation('Custom validation', 'CUSTOM_VALIDATION');
      case 'timeout': throw ToolError.timeout('Custom timeout', 'CUSTOM_TIMEOUT');
      case 'internal': throw ToolError.internal('Custom internal', 'CUSTOM_INTERNAL');
    }
  },
});
```

Note: The factory method signature for rateLimited needs to be checked — if the second param is retryAfterMs, the custom code would be the third param. Adjust the call signature to match the actual API after PRD 4 US-003 is implemented.

