This tests PRD 4 US-008 (removeLocalStorage/removeSessionStorage).

1. **e2e-test plugin** — Add plugins/e2e-test/src/tools/sdk-remove-storage.ts:
```typescript
import { defineTool, removeLocalStorage, removeSessionStorage, getLocalStorage, getSessionStorage } from '@opentabs-dev/plugin-sdk';
import { z } from 'zod';

export const sdkRemoveStorage = defineTool({
  name: 'sdk_remove_storage',
  displayName: 'SDK Remove Storage',
  description: 'Tests removeLocalStorage and removeSessionStorage',
  icon: 'trash',
  input: z.object({
    storageType: z.enum(['local', 'session']),
    key: z.string(),
  }),
  output: z.object({ existed: z.boolean(), afterRemoval: z.boolean() }),
  handle: async (params) => {
    const getter = params.storageType === 'local' ? getLocalStorage : getSessionStorage;
    const existed = getter(params.key) !== null;
    if (params.storageType === 'local') {
      removeLocalStorage(params.key);
    } else {
      removeSessionStorage(params.key);
    }
    const afterRemoval = getter(params.key) !== null;
    return { existed, afterRemoval: afterRemoval };
  },
});
```

2. **E2E test** — Add to e2e/sdk-utilities.e2e.ts:
```typescript
test('removeLocalStorage removes a key', async ({ mcpServer, testServer, extensionContext, mcpClient }) => {
